import{_ as t,o as a,c as o,a6 as r}from"./chunks/framework.DtxWasON.js";const p=JSON.parse('{"title":"VOR Interacting with the DnD example","description":"","frontmatter":{},"headers":[],"relativePath":"vor/guide/interaction.md","filePath":"vor/guide/interaction.md"}'),n={name:"vor/guide/interaction.md"};function i(l,e,s,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="vor-interacting-with-the-dnd-example" tabindex="-1">VOR Interacting with the DnD example <a class="header-anchor" href="#vor-interacting-with-the-dnd-example" aria-label="Permalink to &quot;VOR Interacting with the DnD example&quot;">​</a></h1><p>If you haven&#39;t already, run through the <a href="./implementation.html">full implementation example</a></p><p>This guide assumes you are familiar with Solidity development frameworks such as Truffle/Hardhat.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>The contract will be deployed on Rinkeby testnet. You will need:</p><ol><li>wallets with test Eth - for example from the <a href="https://sepoliafaucet.com/" target="_blank" rel="noreferrer">faucet</a></li><li>xFUNDMOCK tokens for each wallet interacting, including the owner. See <a href="./../contracts.html">contracts</a> for the Rinkeby testnet address, and call the <code>gimme()</code> function to get 10 xFUNDMOCK tokens.</li></ol><h2 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h2><p>Write your deployment script for your contract (this will be dependent on your framework of choice). You will need to pass the two contract values to the <code>constructor</code> for both <code>xFUNDMOCK</code> and the <code>VORCoordinator</code>. These can be obtained from <a href="./../contracts.html">contracts</a>.</p><p>Once you&#39;re ready, deploy your contract on Rinkeby. You can also optionally verify the contract source code on Etherscan.</p><h2 id="initialise" tabindex="-1">Initialise <a class="header-anchor" href="#initialise" aria-label="Permalink to &quot;Initialise&quot;">​</a></h2><p>Once deployed, we need to call a couple of functions to set things up.</p><h3 id="dnd-increasevorallowance" tabindex="-1">DnD.increaseVorAllowance <a class="header-anchor" href="#dnd-increasevorallowance" aria-label="Permalink to &quot;DnD.increaseVorAllowance&quot;">​</a></h3><p>The first thing we need to do is allow the <code>VORCoordinator</code> smart contract to spend xFUNDMOCK on behalf of our DnD smart contract. This allows us to request random numbers, and for the <code>VORCoordinator</code> to transfer fees to the VOR Oracle Provider.</p><p><code>increaseVorAllowance</code> can be called from your framework&#39;s development console, or if you have verified the source code on Etherscan, from their &quot;Write Contract&quot; feature.</p><p>The amount should be suitably high to cover any future costs. Many services (for example Uniswap), do this once with the maximum allowable <code>uint256</code> value &quot;115792089237316195423570985008687907853269984665640564039457584007913129639935&quot;</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>increaseVorAllowance</code> must be called by the wallet that deployed the DnD example smart contract</p></div><h3 id="xfundmock-increaseallowance" tabindex="-1">xFUNDMOCK.increaseAllowance <a class="header-anchor" href="#xfundmock-increaseallowance" aria-label="Permalink to &quot;xFUNDMOCK.increaseAllowance&quot;">​</a></h3><p><em>Each</em> wallet that interacts with the DnD smart contract and intends to call the <code>rollForHit</code> function will need to allow the DnD smart contract to spend xFUNDMOCK tokens on their behalf.</p><p>The <code>increaseAllowance</code> function can be executed on Etherscan (see <a href="./../contracts.html">contracts</a> for the Rinkeby address), using Metamask etc. Similarly, the amount should be sufficiently high, and the <code>spender</code> value should be the address of the deployed DnD smart contract.</p><h3 id="vorcoordinator-getprovidergranularfee" tabindex="-1">VORCoordinator.getProviderGranularFee <a class="header-anchor" href="#vorcoordinator-getprovidergranularfee" aria-label="Permalink to &quot;VORCoordinator.getProviderGranularFee&quot;">​</a></h3><p>It&#39;s good practice to check the current fees for your contract before requesting randomness. This can be done by calling the <a href="./../api/VORCoordinator.html#VORCoordinator-getProviderGranularFee-bytes32-address-">getProviderGranularFee</a> function in the <code>VORCoordinator</code> contract and passing it the <code>keyHash</code> of the provider Oracle you&#39;re requesting from, along with the address of your smart contract.</p><p>The <code>getProviderGranularFee</code> function can be called on Etherscan (see <a href="./../contracts.html">contracts</a>, or via a helper function in your own contract using the <code>IVORCoordinator</code> interface in the <code>ConsumerBase</code> library.</p><h2 id="interact" tabindex="-1">Interact <a class="header-anchor" href="#interact" aria-label="Permalink to &quot;Interact&quot;">​</a></h2><p>Now we have the boring stuff out of the way, we can actually run the game. As before, these functions can be called via your Solidity framework of choice or via Etherscan.</p><h3 id="dnd-addmonster" tabindex="-1">DnD.addMonster <a class="header-anchor" href="#dnd-addmonster" aria-label="Permalink to &quot;DnD.addMonster&quot;">​</a></h3><p>This must be called by the wallet that deployed the contract. It&#39;s possible to add up to 20 monsters, with each one requiring a short name (for example &quot;Orc&quot;), and an AC value between 1 - 20.</p><h3 id="dnd-monsters" tabindex="-1">DnD.monsters <a class="header-anchor" href="#dnd-monsters" aria-label="Permalink to &quot;DnD.monsters&quot;">​</a></h3><p><code>monsters</code> has a built-in getter, which will accept the Id of a monster and retrieve its stats. The result returned will be the name and AC.</p><h3 id="dnd-changestrmodifier" tabindex="-1">DnD.changeStrModifier <a class="header-anchor" href="#dnd-changestrmodifier" aria-label="Permalink to &quot;DnD.changeStrModifier&quot;">​</a></h3><p>Each wallet calling the <code>rollForHit</code> can optionally change their STR modifier, up to 5. This modifier gets added to the d20 roll when the randomness request is fulfilled.</p><h3 id="dnd-rollforhit" tabindex="-1">DnD.rollForHit <a class="header-anchor" href="#dnd-rollforhit" aria-label="Permalink to &quot;DnD.rollForHit&quot;">​</a></h3><p>A wallet can call the <code>rollForHit</code> to generate a random d20 roll to determin if they hit the monster or not. There are 4 required parameters:</p><ol><li>The <code>monsetrId</code> of the monster being hit. See <code>DnD.monsters</code> above</li><li>A <code>seed</code> value - this can be any number, and gets mixed in with the random number generation</li><li>The <code>keyhash</code> for the provider you wish to fulfil the request. This can be obtained from the <a href="./../providers.html">providers</a> page.</li><li>the <code>fee</code> amount required to pay for the request. This will be deducted from the wallet calling this function.</li></ol><p>::: warn A VOR Provider&#39;s base fee is available on the <a href="./../providers.html">providers</a> page or by querying the <code>VORCoordinator</code> smart contract. This is the minimum amount they will accept for fulfilling a request.</p><p>However, providers may also set granular fees on a per-consumer contract basis, because not every contract is the same and more complex consumer contracts will incur higher gas costs for the provider.</p><p>The current fee for your contract can be acquired by calling the <code>VORCoordinator.getProviderGranularFee()</code> function and passing the provider&#39;s <code>keyHash</code> along with the address of your contract.</p><p>The <code>VORCoordinator</code> address is available on the <a href="./../contracts.html">contracts</a> page. :::</p><p>Once a request has been initialised, the VOR Provider Oracle will see a <code>RandomnessRequest</code> event emitted in the <code>VORCoordinator</code> smart contract, generate a random number, and call your contract&#39;s <code>fulfillRandomness</code> function to complete the process.</p><h3 id="dnd-getlastresult" tabindex="-1">DnD.getLastResult <a class="header-anchor" href="#dnd-getlastresult" aria-label="Permalink to &quot;DnD.getLastResult&quot;">​</a></h3><p>It&#39;s possible to monitor the DnD contract&#39;s event logs and watch for the <code>HitResult</code> event. This indicates that the VOR Provider Oracle has fulfilled the randomness request.</p><p>Calling the <code>DnD.getLastResult</code> function requires 2 parameters:</p><ol><li><code>player</code> - the wallet address of the player that rolled</li><li><code>monsterId</code> - the ID of the monster they attempted to hit</li></ol><p>The result returned will be something along the lines of:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[</span></span>
<span class="line"><span>  roll: &#39;17&#39;,</span></span>
<span class="line"><span>  modified: &#39;19&#39;,</span></span>
<span class="line"><span>  result: &#39;hit&#39;,</span></span>
<span class="line"><span>  isRolling: false</span></span>
<span class="line"><span>]</span></span></code></pre></div>`,44)])])}const m=t(n,[["render",i]]);export{p as __pageData,m as default};
